let currentLang = 'en';

function loadLocale(lang) {
  return i18nData[lang] || i18nData['en'];
}

function t(key, replacements = {}) {
  const keys = key.split('.');
  let val = i18nData[currentLang];
  for (const k of keys) {
    if (val == null) break;
    val = val[k];
  }
  if (val == null) {
    // fallback to EN
    val = i18nData['en'];
    for (const k of keys) { if (val == null) break; val = val[k]; }
  }
  if (typeof val !== 'string') return key;
  return val.replace(/\{(\w+)\}/g, (_, k) => replacements[k] ?? `{${k}}`);
}

function setLang(lang, save = true) {
  if (!LANGS.includes(lang)) lang = 'en';
  currentLang = lang;
  if (save) localStorage.setItem(STORAGE_LANG, lang);
  document.documentElement.lang = lang === 'kr' ? 'ht' : lang;
  applyTranslations();
  updateLangToggle(lang);
}

function applyTranslations() {
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.dataset.i18n;
    const val = t(key);
    if (val !== key) el.innerHTML = val;
  });
  document.querySelectorAll('[data-i18n-attr]').forEach(el => {
    const pairs = el.dataset.i18nAttr.split(',');
    pairs.forEach(pair => {
      const [attr, key] = pair.trim().split(':');
      const val = t(key);
      if (val !== key) el.setAttribute(attr, val);
    });
  });
}

function updateLangToggle(lang) {
  document.querySelectorAll('.lang-toggle__btn').forEach(btn => {
    const pressed = btn.dataset.lang === lang;
    btn.setAttribute('aria-pressed', pressed);
  });
}

function detectBrowserLang() {
  const nav = navigator.language || navigator.userLanguage || '';
  const code = nav.toLowerCase().split('-')[0];
  if (code === 'es') return 'es';
  if (code === 'ht' || code === 'hat') return 'kr';
  return 'en';
}

// ─── Language Banner ──────────────────────────────────────────────────────────

function initLangBanner() {
  const saved = localStorage.getItem(STORAGE_LANG);
  if (saved) return; // user has chosen before
  const detected = detectBrowserLang();
  if (detected === 'en') return;
  const banner = document.getElementById('lang-banner');
  if (!banner) return;
  const langName = detected === 'es' ? 'Español' : 'Kreyòl';
  const msgEl = banner.querySelector('[data-lang-banner-msg]');
  if (msgEl) msgEl.textContent = `We detected your browser language. Switch to ${langName}?`;
  banner.removeAttribute('hidden');
  banner.querySelector('[data-lang-banner-accept]')?.addEventListener('click', () => {
    setLang(detected);
    banner.setAttribute('hidden', '');
  });
  banner.querySelector('[data-lang-banner-dismiss]')?.addEventListener('click', () => {
    banner.setAttribute('hidden', '');
    localStorage.setItem(STORAGE_LANG, 'en');
  });
}

// ─── Checklist Progress ───────────────────────────────────────────────────────

function getStorageKey(pageId) {
  return STORAGE_PROGRESS_PREFIX + pageId;
}

function loadProgress(pageId) {
  try {
    return JSON.parse(localStorage.getItem(getStorageKey(pageId)) || '{}');
  } catch { return {}; }
}

function saveProgress(pageId, data) {
  localStorage.setItem(getStorageKey(pageId), JSON.stringify(data));
}

function initChecklist(pageId) {
  const progress = loadProgress(pageId);
  const checkboxes = document.querySelectorAll('.checklist__checkbox[data-check-id]');

  checkboxes.forEach(cb => {
    const id = cb.dataset.checkId;
    if (progress[id]) {
      cb.checked = true;
      cb.closest('.checklist__item')?.classList.add('is-checked');
    }
    cb.addEventListener('change', () => {
      progress[id] = cb.checked;
      saveProgress(pageId, progress);
      cb.closest('.checklist__item')?.classList.toggle('is-checked', cb.checked);
      updateStepCompletion();
      updateProgressBar(pageId);
    });
  });

  updateStepCompletion();
  updateProgressBar(pageId);
}

function updateStepCompletion() {
  document.querySelectorAll('.step-card[data-step-id]').forEach(card => {
    const checks = card.querySelectorAll('.checklist__checkbox[data-check-id]');
    if (checks.length === 0) return;
    const allDone = Array.from(checks).every(c => c.checked);
    card.classList.toggle('is-complete', allDone);
  });
}

function updateProgressBar(pageId) {
  const progress = loadProgress(pageId);
  const allChecks = document.querySelectorAll('.checklist__checkbox[data-check-id]');
  if (allChecks.length === 0) return;
  const done = Array.from(allChecks).filter(c => c.checked).length;
  const pct = Math.round((done / allChecks.length) * 100);

  const fill = document.querySelector('.progress-bar__fill');
  const label = document.querySelector('.progress-label');
  if (fill) fill.style.width = pct + '%';
  if (label) {
    const stepCards = document.querySelectorAll('.step-card[data-step-id]');
    const total = stepCards.length;
    const completedSteps = Array.from(stepCards).filter(c => c.classList.contains('is-complete')).length;
    const labelText = t('lost.progressLabel', { current: completedSteps, total });
    label.textContent = labelText;
  }

  // Show completion card when all checked
  const completionCard = document.querySelector('.completion-card');
  if (completionCard) {
    const allChecks = document.querySelectorAll('.checklist__checkbox[data-check-id]');
    const allDone = Array.from(allChecks).every(c => c.checked);
    completionCard.classList.toggle('visible', allDone);
  }
}

// ─── Expandable ───────────────────────────────────────────────────────────────

function initExpandables() {
  document.querySelectorAll('.expandable__toggle').forEach(btn => {
    btn.addEventListener('click', () => {
      const expanded = btn.getAttribute('aria-expanded') === 'true';
      btn.setAttribute('aria-expanded', !expanded);
      const content = document.getElementById(btn.getAttribute('aria-controls'));
      if (content) content.setAttribute('aria-hidden', expanded);
    });
  });
}

// ─── Resource Category Collapsibles ──────────────────────────────────────────

function initCollapsibles() {
  document.querySelectorAll('.resource-category__header').forEach(btn => {
    const body = document.getElementById(btn.getAttribute('aria-controls'));
    if (!body) return;
    // start open
    btn.setAttribute('aria-expanded', 'true');
    body.removeAttribute('hidden');

    const chevron = btn.querySelector('.resource-category__chevron');

    btn.addEventListener('click', () => {
      const expanded = btn.getAttribute('aria-expanded') === 'true';
      btn.setAttribute('aria-expanded', !expanded);
      body[!expanded ? 'removeAttribute' : 'setAttribute']('hidden', '');
      if (chevron) chevron.style.transform = !expanded ? 'rotate(180deg)' : '';
    });
  });
}

// ─── Copy Buttons ─────────────────────────────────────────────────────────────

function initCopyButtons() {
  document.querySelectorAll('[data-copy]').forEach(btn => {
    btn.addEventListener('click', async () => {
      const text = btn.dataset.copy;
      try {
        await navigator.clipboard.writeText(text);
      } catch {
        const ta = document.createElement('textarea');
        ta.value = text;
        ta.style.cssText = 'position:fixed;opacity:0';
        document.body.appendChild(ta);
        ta.select();
        document.execCommand('copy');
        ta.remove();
      }
      const orig = btn.textContent;
      btn.textContent = t('help.card1Copied');
      btn.classList.add('copied');
      setTimeout(() => {
        btn.textContent = orig;
        btn.classList.remove('copied');
      }, 2000);
    });
  });
}

// ─── Lang Toggle Init ─────────────────────────────────────────────────────────

function initLangToggle() {
  document.querySelectorAll('.lang-toggle__btn').forEach(btn => {
    btn.addEventListener('click', () => {
      setLang(btn.dataset.lang);
    });
  });
}

// ─── Main Init ────────────────────────────────────────────────────────────────

function init() {
  const savedLang = localStorage.getItem(STORAGE_LANG) || detectBrowserLang() || 'en';
  try {
    setLang(savedLang, false);
  } catch (e) {
    console.error('Language init failed:', e);
    currentLang = 'en';
  }

  initLangToggle();
  initLangBanner();
  initExpandables();
  initCollapsibles();
  initCopyButtons();

  const pageId = document.body.dataset.pageId;
  if (pageId) {
    initChecklist(pageId);
  }
}

document.addEventListener('DOMContentLoaded', init);
